// src/views/user/MyProfile/composables/useModules.js
import { ref } from 'vue'
import profile from '@/api/profile'

export function useModules() {
  const loading = ref(false)
  const activeModules = ref([])
  const inactiveModules = ref([])

  // 获取模块数据
  const fetchModulesData = async () => {
    try {
      loading.value = true
      const response = await profile.getModules()
      console.log('【模块数据】服务器返回的模块数据:', response.data)

      if (response?.data?.code === 200) {
        const { active = [], inactive = [] } = response.data.data
        activeModules.value = active
        inactiveModules.value = inactive
        console.log('【模块数据】处理后的活动模块:', activeModules.value)
        console.log('【模块数据】处理后的未激活模块:', inactiveModules.value)
      }
    } catch (error) {
      console.error('获取模块数据失败:', error)
    } finally {
      loading.value = false
    }
  }

  // 添加模块
  const addModule = async (moduleType) => {
    try {
      loading.value = true
      console.log('【模块数据】准备添加模块:', moduleType)
      console.log('【模块数据】添加前的活动模块:', activeModules.value)

      const response = await profile.addModule(moduleType)
      console.log('【模块数据】服务器返回的添加结果:', response.data)

      if (response?.data?.code === 200) {
        // 重新获取模块数据以确保同步
        await fetchModulesData()
        console.log('【模块数据】添加后重新获取的模块数据:', {
          active: activeModules.value,
          inactive: inactiveModules.value
        })
      }
    } catch (error) {
      console.error('添加模块失败:', error)
    } finally {
      loading.value = false
    }
  }

  // 移除模块
  const removeModule = async (moduleType) => {
    try {
      loading.value = true
      console.log('【模块数据】准备移除模块:', moduleType)
      console.log('【模块数据】移除前的活动模块:', activeModules.value)

      const response = await profile.removeModule(moduleType)
      console.log('【模块数据】服务器返回的移除结果:', response.data)

      if (response?.data?.code === 200) {
        // 重新获取模块数据以确保同步
        await fetchModulesData()
        console.log('【模块数据】移除后重新获取的模块数据:', {
          active: activeModules.value,
          inactive: inactiveModules.value
        })
      }
    } catch (error) {
      console.error('移除模块失败:', error)
    } finally {
      loading.value = false
    }
  }

  return {
    loading,
    activeModules,
    inactiveModules,
    fetchModulesData,
    addModule,
    removeModule
  }
}
